from typing import Any

from pydantic import BaseModel

from src.agents.specs import AgentSpec
from src.agents.state import AgentState


def _dump(value: Any) -> Any:
    if isinstance(value, BaseModel):
        return value.model_dump(mode="json")
    if isinstance(value, list):
        return [_dump(item) for item in value]
    if isinstance(value, dict):
        return {key: _dump(item) for key, item in value.items()}
    return value


def assemble(spec: AgentSpec, state: AgentState) -> list[dict[str, Any]]:
    """Build a small, stable message list using only `spec.reads` slices."""
    sliced = {key: _dump(state[key]) for key in spec.reads if key in state}
    return [
        {"role": "system", "content": spec.prompt, "tools": spec.tools},
        {"role": "user", "content": sliced},
    ]

from __future__ import annotations

from typing import Any

from src.agents.specs import AgentSpec
from src.agents.tools import TOOL_REGISTRY


def dispatch(spec: AgentSpec, tool_name: str, args: dict[str, Any]) -> dict[str, Any]:
    """Run a whitelisted tool.

    The whitelist is enforced here, not in prompts.
    """
    if tool_name not in spec.tools:
        return {"error": f"tool '{tool_name}' is not allowed for agent '{spec.name}'"}
    tool = TOOL_REGISTRY.get(tool_name)
    if tool is None:
        return {"error": f"tool '{tool_name}' is not registered"}
    try:
        result = tool.invoke(args)
    except Exception as exc:
        return {"error": str(exc)}
    if isinstance(result, dict):
        return result
    return {"result": result}

